  1→import { useInfiniteQuery } from '@tanstack/react-query';
  2→import './sidebarOpinions.css'
  3→import { getOpinions } from '../../../API/Api';
  4→import { useNavigate } from 'react-router-dom';
  5→import { handleClickProfile } from '../../../helpers/handleClicks';
  6→import { useAuth } from '../../Context/useAuth';
  7→import { BarLoader, MoonLoader } from 'react-spinners';
  8→import VerifiedBadge from '../Badge/VerifiedBadge';
  9→import { useEffect } from 'react';
 10→import MentionText from '../mentions/MentionText';
 11→
 12→const SidebarOpinions = ({openEditor}) =>{
 13→    const {user, session, openAuthModal} = useAuth();
 14→
 15→    const handleOpenEditor = () =>{
 16→        if(!session) return openAuthModal();
 17→        openEditor();
 18→    }
 19→    const navigate = useNavigate();
 20→
 21→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
 22→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
 23→        if(!session){
 24→            e.stopPropagation();
 25→            return openAuthModal();
 26→        }
 27→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
 28→    };
 29→
 30→    const {data, isLoading, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 31→        queryKey: ['getOpinions'],
 32→        queryFn: ({pageParam = null}) => getOpinions(pageParam, 5),
 33→        getNextPageParam: (lastPage) =>{
 34→            if(lastPage?.hasMore){
 35→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
 36→                return lastOpinion.id;
 37→            } else {
 38→                return undefined
 39→            }
 40→        },
 41→        refetchOnWindowFocus: false,
 42→        staleTime: 1000 * 60 * 5,
 43→    });
 44→
 45→    const handleClickSeeMore = () =>{
 46→        if(!isLoading && !isFetchingNextPage){
 47→            fetchNextPage();;
 48→        }
 49→        
 50→    }
 51→
 52→    const handleClickContent = (e, opinionId, userId) =>{
 53→        e.stopPropagation();
 54→        if(!session) return openAuthModal();
 55→        navigate('/home/opinionsViewer', {
 56→            state: {
 57→                opinionId: opinionId,
 58→                userId: userId
 59→            }
 60→        })
 61→    }
 62→
 63→    useEffect(() => {
 64→        // console.log(data)
 65→    }, [data])
 66→
 67→    const getUserHandle = (opinionUser) => {
 68→        if(!opinionUser?.user_email) return null;
 69→        const handle = opinionUser.user_email.split('@')[0];
 70→        return handle ? `@${handle}` : null;
 71→    }
 72→
 73→    const opinions = data?.pages.flatMap((page) => page.data) || [];
 74→    
 75→    if(opinions.length === 0){
 76→        return(
 77→            <div className='side-bar-opinions-parent-container'>
 78→                <div className='signal-container'>
 79→                    <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
 80→                    <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
 81→                        Write opinions
 82→                    </button>
 83→                </div>
 84→                <div className='latest-opinions-container'>
 85→                    <div className='latest-opinions-header'>
 86→                        Latest opinions
 87→                    </div>
 88→                    <div className='sidebar-opinions-cards-container'>
 89→                        No opinions availabe
 90→                    </div>
 91→                </div>
 92→            </div>
 93→        )
 94→    }
 95→    if(isLoading){
 96→        return(
 97→            <div className='side-bar-opinions-parent-container'>
 98→                <div className='opinions-loading-container'>
 99→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
100→                </div>
101→            </div>
102→        )
103→    }
104→    return(
105→        <>
106→        <div className="side-bar-opinions-parent-container">
107→            <div className='signal-container'>
108→                <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
109→                <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
110→                    Write opinions
111→                </button>
112→            </div>
113→
114→            <div className='latest-opinions-container'>
115→                <div className='latest-opinions-header'>
116→                    Latest opinions
117→                </div>
118→                <div className='sidebar-opinions-cards-container'>
119→                    {opinions.map((opinionsData) => {
120→                        const handle = getUserHandle(opinionsData?.users);
121→                        return (
122→                            <div key={opinionsData.id} className="so-card-wrapper">
123→                                <div className="so-card so-card--flat">
124→                                    <div className="so-card-content">
125→                                        <div className="so-user-row">
126→                                            <div className="so-user-meta">
127→                                                <div className={`so-avatar-outer ${opinionsData.users.badge === 'legend' ? 'avatar-ring-legend' : opinionsData.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
128→                                                    <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-avatar" src={opinionsData.users.image_url || "../../assets/profile.jpg"} alt={`${opinionsData?.users?.name || "User"} profile picture`} />
129→                                                </div>
130→                                                <div className="so-name-block">
131→                                                    <div className="so-name-line">
132→                                                        <span onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-username">{opinionsData.users.name}</span>
133→                                                        <VerifiedBadge badge={opinionsData.users.badge} size={14} />
134→                                                    </div>
135→                                                    {handle && (
136→                                                        <span className="so-handle">{handle}</span>
137→                                                    )}
138→                                                </div>
139→                                            </div>
140→                                        </div>
141→                                        <div className="so-body" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
142→                                            <MentionText text={opinionsData.opinion} />
143→                                        </div>
144→                                        <div className="so-meta-bar">
145→                                            <span className="so-reply-pill" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinionsData.id, userId: opinionsData.user_id } }); }}>
146→                                                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
147→                                                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
148→                                                </svg>
149→                                                Reply
150→                                            </span>
151→                                        </div>
152→                                    </div>
153→                                </div>
154→                            </div>
155→                        )
156→                    })}
157→                    {hasNextPage && (
158→                        <div onClick={() => handleClickSeeMore()} className='see-fullpage-bttn'>
159→                            See more
160→                        </div>
161→                    )}
162→                    
163→                </div>
164→            </div>
165→        </div>
166→        </>
167→    )
168→}
169→export default SidebarOpinions;
