  1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  2→import { addReplyOpinion, getOpinionReply } from "../../../API/Api";
  3→import { useState, useRef } from "react";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { motion, AnimatePresence } from "framer-motion";
  6→import formatPostDate from "../../../helpers/formatDateString";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→import MentionText from "../mentions/MentionText";
  9→import useTextareaMention from "../mentions/useTextareaMention";
 10→import MentionDropdown from "../mentions/MentionDropdown";
 11→
 12→const MAX_VISUAL_DEPTH = 4;
 13→
 14→const OpinionsReplyCard = ({ opinionId, depth = 0 }) => {
 15→    const queryClient = useQueryClient();
 16→    const { user, session } = useAuth();
 17→
 18→    const [showReply, setShowReply] = useState(false);
 19→    const [replyOpinion, setReplyOpinion] = useState('');
 20→    const [isTypingId, setIsTypingId] = useState('');
 21→    const [showReplyButtonId, setShowReplyButtonId] = useState('');
 22→
 23→    const textAreaRef = useRef(null);
 24→
 25→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(replyOpinion, setReplyOpinion, textAreaRef, 280, user?.userData?.[0]?.id);
 26→
 27→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
 28→        queryKey: ['getReplyOpinion', opinionId],
 29→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
 30→        getNextPageParam: (lastPage) => {
 31→            if (lastPage?.hasMore) {
 32→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 33→                return lastReply.id;
 34→            }
 35→            return undefined;
 36→        },
 37→        enabled: !!opinionId,
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 60 * 5
 40→    });
 41→
 42→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 43→        try {
 44→            const formadata = new FormData();
 45→            formadata.append('opinion', reply);
 46→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 47→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 48→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 49→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 50→            setReplyOpinion('');
 51→        } catch (error) {
 52→            console.error(error);
 53→            setReplyOpinion('');
 54→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 55→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 56→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 57→        }
 58→    };
 59→
 60→    const cancelTyping = () => {
 61→        setIsTypingId('');
 62→        setReplyOpinion('');
 63→        if (textAreaRef.current) {
 64→            textAreaRef.current.blur();
 65→        }
 66→        setShowReplyButtonId('');
 67→    };
 68→
 69→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
 70→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
 71→
 72→    return (
 73→        <div
 74→            className="rc-thread"
 75→            style={{ '--depth': visualDepth }}
 76→        >
 77→            {opinioData?.map((opinion, index) => (
 78→                <motion.div
 79→                    className="so-card-wrapper rc-card"
 80→                    key={opinion.id}
 81→                    initial={{ opacity: 0, y: 6 }}
 82→                    animate={{ opacity: 1, y: 0 }}
 83→                    transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
 84→                >
 85→                    {depth > 0 && <div className="rc-thread-line" />}
 86→
 87→                    <div className="so-card so-card--flat">
 88→                        <div className="so-card-content">
 89→                            <div className="so-user-row">
 90→                                <div className="so-user-meta">
 91→                                    <div className={`so-avatar-outer ${opinion.users?.badge === 'legend' ? 'avatar-ring-legend' : opinion.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 92→                                        <img
 93→                                            className="so-avatar"
 94→                                            src={opinion.users?.image_url || '../assets/profile.jpg'}
 95→                                            alt={`${opinion?.users?.name || "User"} profile picture`}
